onClick:
{{
(async () => {

  // 1. Jeżeli nie jest wymuszona zmiana hasła,
  // użytkownik musi podać aktualne hasło
  if (
    !appsmith.store.session.user.mustChangePassword &&
    !InputCurrentPassword.text.trim()
  ) {
    showAlert("Podaj aktualne hasło.", "warning");
    return;
  }

  // 2. Nowe hasło
  if (!InputNewPassword.text.trim()) {
    showAlert("Podaj nowe hasło.", "warning");
    return;
  }

  // 3. Walidacja hasła z widgetu
  if (!InputNewPassword.isValid) {
    showAlert(
      "Hasło nie spełnia wymagań bezpieczeństwa.",
      "warning"
    );
    return;
  }

  // 4. Powtórzenie hasła
  if (!InputRepeatPassword.text.trim()) {
    showAlert("Powtórz nowe hasło.", "warning");
    return;
  }

  // 5. Oba hasła muszą być identyczne
  if (InputNewPassword.text !== InputRepeatPassword.text) {
    showAlert(
      "Nowe hasła nie są identyczne.",
      "warning"
    );
    return;
  }

  // 6. Jeżeli użytkownik sam zmienia hasło,
  // sprawdzamy poprawność aktualnego hasła
  if (!appsmith.store.session.user.mustChangePassword) {

    await checkCurrentPassword.run();

    if (!checkCurrentPassword.data?.[0]?.password_ok) {

      showAlert(
        "Aktualne hasło jest nieprawidłowe.",
        "warning"
      );

      return;
    }

  }

  // 7. Sprawdzenie czy nowe hasło
  // nie jest takie samo jak obecne
  await checkPasswordReuse.run();

  if (checkPasswordReuse.data?.[0]?.same_password) {

    showAlert(
      "Nowe hasło musi różnić się od obecnego.",
      "warning"
    );

    return;
  }

  // 8. Zmiana hasła
  await changeOwnPassword.run();

  // 9. Wylogowanie bieżącej sesji
  await authLogoutSession.run();

  // 10. Wyczyść store
  await clearStore();

  // 11. Wyczyść formularz
  resetWidget("InputCurrentPassword", true);
  resetWidget("InputNewPassword", true);
  resetWidget("InputRepeatPassword", true);

  // 12. Komunikat
  showAlert(
    "Hasło zostało zmienione. Zaloguj się ponownie.",
    "success"
  );

  // 13. Powrót do logowania
  navigateTo("Logowanie");

})();
}}
